package com.chaobo.scm.supplier.infrastructure.integration;
import com.chaobo.scm.common.error.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Component;import java.time.*;import java.util.concurrent.ConcurrentHashMap;import java.util.function.Supplier;
@Component public class RemoteCallCircuitBreaker{private final int threshold;private final Duration openDuration;private final ConcurrentHashMap<String,State> states=new ConcurrentHashMap<>();public RemoteCallCircuitBreaker(@Value("${scm.integration.circuit.failure-threshold:5}")int threshold,@Value("${scm.integration.circuit.open-seconds:30}")long seconds){this.threshold=threshold;this.openDuration=Duration.ofSeconds(seconds);}public<T>T execute(String target,Supplier<T> action){var state=states.computeIfAbsent(target,k->new State());synchronized(state){if(state.openedAt!=null&&state.openedAt.plus(openDuration).isAfter(Instant.now()))throw new BusinessException(ErrorCode.EXTERNAL_CALL_FAILED,target+"远程调用已熔断");if(state.openedAt!=null)state.openedAt=null;}try{T result=action.get();synchronized(state){state.failures=0;state.openedAt=null;}return result;}catch(RuntimeException e){synchronized(state){if(++state.failures>=threshold)state.openedAt=Instant.now();}throw e;}}private static final class State{int failures;Instant openedAt;}}
